//catalog actions view
if (document.querySelector('.js-button-rows')) {
	document.querySelector('.js-button-rows').addEventListener('click', function (e) {
		document.querySelector('.js-button-tiles').classList.remove('active')
		this.classList.add('active')
		document.querySelector('.catalog-box').classList.add('view-rows')
		e.preventDefault()
		e.stopPropagation()
		return false
	})
	document.querySelector('.js-button-tiles').addEventListener('click', function (e) {
		document.querySelector('.js-button-rows').classList.remove('active')
		this.classList.add('active')
		document.querySelector('.catalog-box').classList.remove('view-rows')
		e.preventDefault()
		e.stopPropagation()
		return false
	})
}

//js popup wrap
const togglePopupButtons = document.querySelectorAll('.js-btn-popup-toggle')
const closePopupButtons = document.querySelectorAll('.js-btn-popup-close')
const popupElements = document.querySelectorAll('.js-popup-wrap')
const wrapWidth = document.querySelector('.wrap').offsetWidth
const bodyElem = document.querySelector('body')

function popupElementsClear() {
	document.body.classList.remove('menu-show')
	document.body.classList.remove('filter-show')
	document.body.classList.remove('search-show')
	popupElements.forEach(element => element.classList.remove('popup-right'))
}

function popupElementsClose() {
	togglePopupButtons.forEach(element => {
		if (!element.closest('.no-close')) {
			element.classList.remove('active')
		}
	})
}

function popupElementsContentPositionClass() {
	popupElements.forEach(element => {
		let pLeft = element.offsetLeft
		let pWidth = element.querySelector('.js-popup-block').offsetWidth
		let pMax = pLeft + pWidth;
		if (pMax > wrapWidth) {
			element.classList.add('popup-right')
		} else {
			element.classList.remove('popup-right')
		}
	})
}

for (i = 0; i < togglePopupButtons.length; i++) {
	togglePopupButtons[i].addEventListener('click', function (e) {
		popupElementsClear()
		if (this.classList.contains('active')) {
			this.classList.remove('active')
		} else {
			popupElementsClose()
			this.classList.add('active')
			if (this.closest('.popup-menu-wrap')) {
				document.body.classList.add('menu-show')
			}
			if (this.closest('.popup-search-wrap')) {
				document.body.classList.add('search-show')
			}
			if (this.closest('.popup-filter-wrap')) {
				document.body.classList.add('filter-show')
			}
			popupElementsContentPositionClass()
		}
		if (!this.classList.contains('js-popup-open')) {
			e.preventDefault()
			e.stopPropagation()
			return false
		}
	})
}
for (i = 0; i < closePopupButtons.length; i++) {
	closePopupButtons[i].addEventListener('click', function (e) {
		popupElementsClear()
		popupElementsClose()
		e.preventDefault()
		e.stopPropagation()
		return false;
	})
}
document.onclick = function (event) {
	if (!event.target.closest('.js-popup-block')) {
		popupElementsClear()
		popupElementsClose()
	}
}
popupElements.forEach(element => {
	if (element.classList.contains('js-popup-select')) {
		let popupElementSelectItem = element.querySelectorAll('.js-popup-block li a')
		if (element.querySelector('.js-popup-block .active')) {
			element.classList.add('select-active')
			let popupElementActive = element.querySelector('.js-popup-block .active').innerHTML
			let popupElementButton = element.querySelector('.js-btn-popup-toggle')
			popupElementButton.innerHTML = ''
			popupElementButton.insertAdjacentHTML('beforeend', popupElementActive)
		} else {
			element.classList.remove('select-active')
		}
		for (i = 0; i < popupElementSelectItem.length; i++) {
			popupElementSelectItem[i].addEventListener('click', function (e) {
				this.closest('.js-popup-wrap').classList.add('select-active')
				if (this.closest('.js-popup-wrap').querySelector('.js-popup-block .active')) {
					this.closest('.js-popup-wrap').querySelector('.js-popup-block .active').classList.remove('active')
				}
				this.classList.add('active')
				let popupElementActive = element.querySelector('.js-popup-block .active').innerHTML
				let popupElementButton = element.querySelector('.js-btn-popup-toggle')
				popupElementButton.innerHTML = ''
				popupElementButton.insertAdjacentHTML('beforeend', popupElementActive)
				popupElementsClear()
				popupElementsClose()
				if (!this.closest('.js-tabs-nav')) {
					e.preventDefault()
					e.stopPropagation()
					return false
				}
			})
		}
	}
})

//mobile menu
const submenuMenuButton = document.querySelectorAll('.popup-menu-wrap .submenu .btn-submenu')
const submenuButtonBack = document.querySelector('.popup-menu-wrap .btn-submenu-back')
for (i = 0; i < submenuMenuButton.length; i++) {
	submenuMenuButton[i].addEventListener('click', function(e) {
		if (wrapWidth < 1024) {
			this.classList.toggle('opened')
			bodyElem.classList.toggle('submenu-opened')
			e.preventDefault()
			e.stopPropagation()
			return false
		}
	})
}
submenuButtonBack.addEventListener('click', function(e) {
	document.querySelector('.opened').classList.remove('opened')
	bodyElem.classList.remove('submenu-opened')
	e.preventDefault()
	e.stopPropagation()
	return false
})

//button scroll up
let buttonUp = document.getElementById("up");
buttonUp.addEventListener('click', function(e) {
	window.scrollTo({top: 0, behavior: 'smooth'});
	e.preventDefault()
	e.stopPropagation()
})
window.onscroll = function() {scrollFunction()}
function scrollFunction() {
	let buttonShowScroll = document.body.clientHeight * 1.6
	console.log(buttonShowScroll)
	if (document.body.scrollTop > buttonShowScroll || document.documentElement.scrollTop > buttonShowScroll) {
		buttonUp.style.display = "block";
	} else {
		buttonUp.style.display = "none";
	}
}
scrollFunction()

//js tabs
const tabsNav = document.querySelectorAll('.js-tabs-nav')
const tabsBlocks = document.querySelectorAll('.js-tab-block')

function tabsActiveStart() {
	for (iTab = 0; iTab < tabsBlocks.length; iTab++) {
		if (tabsBlocks[iTab].classList.contains('active')) {
			tabsBlocks[iTab].classList.remove('active')
		}
	}
	for (i = 0; i < tabsNav.length; i++) {
		let tabsNavElements = tabsNav[i].querySelectorAll('[data-tab]')
		for (iElements = 0; iElements < tabsNavElements.length; iElements++) {
			if (tabsNavElements[iElements].classList.contains('active')) {
				let tabsNavElementActive = tabsNavElements[iElements].dataset.tab
				for (j = 0; j < tabsBlocks.length; j++) {
					if (tabsBlocks[j].dataset.tab.toString().indexOf(tabsNavElementActive) > -1) {
						tabsBlocks[j].classList.add('active')
					}
				}
			}
		}
	}
	
}

for (i = 0; i < tabsNav.length; i++) {
	tabsNav[i].addEventListener('click', function (e) {
		if (e.target.closest('[data-tab]')) {
			let tabsNavElements = this.querySelector('[data-tab].active')
			tabsNavElements ? tabsNavElements.classList.remove('active') : false
			e.target.closest('[data-tab]').classList.add('active')
			tabsActiveStart()
			e.preventDefault()
			e.stopPropagation()
			return false
		}
	})
}
tabsActiveStart()

//input range
const rangeInputs = document.querySelectorAll('input[type="range"]')
for (i = 0; i < rangeInputs.length; i++) {
	let target = rangeInputs[i]
	const min = target.min
	const max = target.max
	const val = target.value
	let percentage = (val - min) * 100 / (max - min)
	target.style.backgroundSize = percentage + '% 100%'
	rangeResult = rangeInputs[i].value
	rangeInputs[i].parentNode.querySelector('.field-range-result').textContent = rangeResult
	rangeInputs[i].addEventListener('change', function (e) {
		rangeResult = this.value
		this.parentNode.querySelector('.field-range-result').textContent = rangeResult
	})
}

function handleInputChange(e) {
	let target = e.target
	const min = target.min
	const max = target.max
	const val = target.value
	let percentage = (val - min) * 100 / (max - min)
	target.style.backgroundSize = percentage + '% 100%'
	for (i = 0; i < rangeInputs.length; i++) {
		rangeResult = rangeInputs[i].value
		rangeInputs[i].parentNode.querySelector('.field-range-result').textContent = rangeResult
		rangeInputs[i].addEventListener('change', function (e) {
			rangeResult = this.value
			this.parentNode.querySelector('.field-range-result').textContent = rangeResult
		})
	}
}

rangeInputs.forEach(input => {
	input.addEventListener('input', handleInputChange)
})



//filter toggle
const filterButtonToggle = document.querySelectorAll('.js-filter-toggle')
const filterBox = document.querySelector('.js-filter')
for (i = 0; i < filterButtonToggle.length; i++) {
	filterButtonToggle[i].addEventListener('click', function(e) {
		filterBox.classList.toggle('active')
		e.preventDefault()
		e.stopPropagation()
		return false
	})
}


//btn tgl
let tglButtons = document.querySelectorAll('.js-btn-tgl')
for (i = 0; i < tglButtons.length; i++) {
	tglButtons[i].addEventListener('click', function (e) {
		this.classList.contains('active') ? this.classList.remove('active') : this.classList.add('active')
		e.preventDefault()
		e.stopPropagation()
		return false
	})
}


//js tab features activate
const buttonTabFeaturesActivate = document.querySelector('.js-tab-features-activate')
const buttonTabFeatureTop = (innerWidth < 1024) ? document.querySelector('.tabs-box').offsetTop : document.querySelector('.tabs-box').offsetTop + 90
if (buttonTabFeaturesActivate) {
	buttonTabFeaturesActivate.addEventListener('click', function(e) {
		document.querySelector('.btn-tab[data-tab=card-tab02]').click()
		window.scrollTo({top: buttonTabFeatureTop, behavior: 'smooth'})
		e.preventDefault()
		e.stopPropagation()
		return false
	})
}

//table
const tableContent = document.querySelector('.table-box table')
const tableScrollWrap = document.querySelector('.table-box .tbl-inner-wrap')
if (tableContent) {
	const tableWrap = document.querySelector('.table-box')
	const tableContentWidth = document.querySelector('.table-box table').clientWidth
	const tableWrapWidth = document.querySelector('.table-box').clientWidth
	const tableScrollWrapWidth = document.querySelector('.table-box .tbl-inner-wrap').clientWidth
	const tableFixedLeft = document.querySelector('.table-box .td-fixed').previousElementSibling.clientWidth
	tableScrollFix()
	if (tableScrollWrap) {
		tableScrollWrap.addEventListener('scroll', function() {
			if ((tableScrollWrapWidth + tableScrollWrap.scrollLeft) === tableContentWidth) {
				tableWrap.classList.remove('table-scroll')
			} else {
				tableWrap.classList.add('table-scroll')
			}
			if (tableScrollWrap.scrollLeft  > tableFixedLeft) {
				tableWrap.classList.add('table-fixed')
			} else {
				tableWrap.classList.remove('table-fixed')
			}
		})
	}
	function tableScrollFix() {
		if (tableContentWidth > tableWrapWidth) {
			tableWrap.classList.add('table-scroll')
		} else {
			tableWrap.classList.remove('table-scroll')
		}
	}
}

/* End */
